using namespace bit;
int extendedEuclidean(int a, int b, int&x, int& y) {
  if(b == 0) {
    x = 1;
    y = 0;
    return a;
  }
  int x1, y1;
  int d = extendedEuclidean(b, a%b, x1, y1);
  x = y1;
  y = x1 - y1*(a/b);
  return d;
}

int binPower(int a, int b, int m = mod) {
  if(b == 0) {
    return 1ll;
  }
  int res = binPower(a, b / 2, m);
  if(b % 2 == 0) {
    return (res * res) % m;
  } else {
    return (((res * res) % m) * a) % m;
  }
}


int binPowerNoMod(int a, int b) {
  if(b == 0) {
    return 1ll;
  }
  int res = binPowerNoMod(a, b / 2);
  if(b % 2 == 0) {
    return (res * res);
  } else {
    return (((res * res)) * a);
  }
}


int inv(int a, int b){
 return 1<a ? b - inv(b%a,a)*b/a : 1;
}


pair<v, v> linear_sieve(int n) {
  //https://cp-algorithms.com/algebra/prime-sieve-linear.html
  vector<int> lp(n + 1, 0);
  vector<int> primes;
  loop(i, 2, n + 1) {
    if(lp[i] == 0) {
      primes.pb(i);
      lp[i] = i;
    }
    for(int j = 0; i * primes[j] <= n; j++) {
      lp[primes[j] * i] = primes[j];
      if(primes[j] == lp[i])break;
    }
  }
  return pair<v, v>{lp, primes};
}

