}

int ceil_div(int a, int b) {
  if(a > 0 && b < 0 || a < 0 && b > 0) {
    return a/b;
  }
  if(a % b == 0)
    return a / b;
  else return (a / b) + 1;
}

int lcm(int a, int b) {
  int g = __gcd(a, b);
  int l = b / g;
  l = l * a;
  return l;
}

