vector<int> topoSort(int n, vector<vector<int>> &adj) {
    vector<int> indeg(n+1, 0);
    for (int i = 1; i <= n; i++) {
        for (int v : adj[i]) indeg[v]++;
    }
    queue<int> q;
    for (int i = 1; i <= n; i++) if (indeg[i] == 0) q.push(i);
    vector<int> topo;
    while (!q.empty()) {
        int u = q.front(); q.pop();
        topo.push_back(u);
        for (int v : adj[u]) {
            indeg[v]--;
            if (indeg[v] == 0) q.push(v);
        }
    }

    if(topo.size()!=n)
    {
