void bfs(int start,vector<vector<int>> &adj) 
{
    int n=adj.size()-1;
    queue<int> q;
    q.push(start);
    vector<int> dist(n+1,-1);
    dist[start] = 0;

    while (!q.empty()) {
        int i = q.front();
        q.pop();

        for (int x : adj[i]) {
