vector<pair<int,int>> oper(string s)
{
    int n=s.size();
    int alter=1;
    vector<pair<int,int>> op;
    for(int i=1;i<n;i++)
    {
        if(s[i]==s[i-1]) 
        {
            alter=0;
            break;
        }
    }
    if(alter)
    {
        op.push_back(make_pair(0,2));
        s[0]=(s[0]-'0')^1+'0';
        s[1]=(s[1]-'0')^1+'0';
        s[2]=(s[2]-'0')^1+'0';
    }
    int i;
    for(i=1;i<n;i++)
    {
        if(s[i]==s[i-1])
        {
            break;
        }
    }
    int L=i-1;
    int R=i;
    int sign;
    //cout<<L<<R<<"here"<<endl;
    if(s[L]=='0') sign=0;
    else sign=1;
    //cout<<sign<<endl;

    while(L>0)
    {
        if(s[L]==s[L-1]) L--;
        else
        {
            op.push_back(make_pair(L,R));
            sign=sign^1;
            //cout<<sign<<endl;
            L--;
        }
    }
    //cout<<sign<<endl;
    s[R]=sign+'0';
    while(R<n-1)
    {
        //cout<<R<<" "<<s[R]<<" "<<s[R+1]<<endl;
        if(s[R]==s[R+1]) R++;
        else
        {
            op.push_back(make_pair(L,R));
            sign=sign^1;
            //cout<<sign<<endl;
            R++;
        }
    }
    if(sign==1)
    op.push_back(make_pair(0,n-1));

    return op;
}


